# Iterative version (using a loop)
def factorial_loop(n):
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

# Recursive version
def factorial_recursive(n):
    if n <= 1:
        return 1
    return n * factorial_recursive(n - 1)

print(factorial_loop(5))      # 120
print(factorial_recursive(5)) # 120
